func (m *manager) get(key string) *item {
	var it *item
	if m.storage != nil {
		it = m.acquire()
		raw, err := m.storage.Get(key)
		if err != nil {
			return it
		}
		if raw != nil {
			if _, err := it.UnmarshalMsg(raw); err != nil {
				return it
			}
		}
		return it
	}
	if it, _ = m.memory.Get(key).(*item); it == nil {
		return nil
	}
	return it
}
